import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/idea-community.CV-Uvcck.js";const a=JSON.parse(`{"title":"建置開發環境","description":"關於建置 Fabric 開發環境的逐步指南。","frontmatter":{"title":"建置開發環境","description":"關於建置 Fabric 開發環境的逐步指南。","authors":["2xsaiko","andrew6rant","asiekierka","daomephsta","falseresync","IMB11","liach","mkpoli","modmuss50","natanfudge","SolidBlock-cn","telepathicgrunt"],"authors-nogithub":["siglong"],"files":[]},"headers":[],"relativePath":"zh_tw/1.21.8/develop/getting-started/setting-up-a-development-environment.md","filePath":"versions/1.21.8/translated/zh_tw/develop/getting-started/setting-up-a-development-environment.md","lastUpdated":1760721669000}`);var o={name:`zh_tw/1.21.8/develop/getting-started/setting-up-a-development-environment.md`};function s(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">建置開發環境 <a class="header-anchor" href="#h1" aria-label="Permalink to “建置開發環境”">​</a></h1><p>要開始用 Fabric 開發模組，需要使用 IntelliJ IDEA 建置開發環境。</p><h2 id="installing-jdk-21" tabindex="-1">安裝 JDK 21 <a class="header-anchor" href="#installing-jdk-21" aria-label="Permalink to “安裝 JDK 21”">​</a></h2><p>要開發 Minecraft 1.21 的模組，你需要 JDK 21。</p><p>如果你需要安裝 Java 的幫助，可以參考 <a href="./../../players/index">player guides section</a> 中的各種 Java 安裝指南。</p><h2 id="installing-intellij-idea" tabindex="-1">安裝 IntelliJ IDEA <a class="header-anchor" href="#installing-intellij-idea" aria-label="Permalink to “安裝 IntelliJ IDEA”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>你當然可以使用其他 IDE，如 Eclipse 或 Visual Studio Code，但本文檔站上的大多數頁面都假設你使用的是 IntelliJ IDEA。如果你使用其他 IDE，請參考該 IDE 的文檔。</p></div><p>如果沒有安裝 IntelliJ IDEA，你可以從 <a href="https://www.jetbrains.com/idea/download/" target="_blank" rel="noreferrer">官網</a> 下載 - 按照你的作業系統的安裝步驟操作。</p><p>IntelliJ IDEA 的 Community 版本是免費且開源的，是使用 Fabric 開發模組的推薦版本。</p><p>你可能需要向下滑動才能找到 Community 版的下載連結 - 如下圖所示:</p><p><img src="/assets/develop/getting-started/idea-community.png" alt="IDEA Community Edition Download Prompt" loading="lazy"></p><h2 id="installing-idea-plugins" tabindex="-1">安裝 IDEA 插件 <a class="header-anchor" href="#installing-idea-plugins" aria-label="Permalink to “安裝 IDEA 插件”">​</a></h2><p>雖然這些插件並不是必要的，但可以讓使用 Fabric 開發模組更加容易 - 你應該考慮安裝它們。</p><h3 id="minecraft-development" tabindex="-1">Minecraft Development <a class="header-anchor" href="#minecraft-development" aria-label="Permalink to “Minecraft Development”">​</a></h3><p>Minecraft Development 插件提供對 Fabric 模組開發提供支援，是要安裝的最重要的插件。</p><p>你可以通過打開IntelliJ IDEA，然後前往 <code>File &gt; Settings &gt; Plugins &gt; Marketplace Tab</code> - 在搜索欄中搜尋 <code>Minecraft Development</code>，然後點擊 <code>Install</code> 按鈕來安裝它。</p><p>你可以通過打開IntelliJ IDEA，然後前往 <code>File &gt; Settings &gt; Plugins &gt; Marketplace Tab</code> - 在搜索欄中搜尋 <code>Minecraft Development</code>，然後點擊 <code>Install</code> 按鈕來安裝它。</p>`,17)]])}var c=r(o,[[`render`,s]]);export{a as __pageData,c as default};